"use client";

import { useState, useEffect, useCallback } from "react";

type Product = { id: number; name: string; price: number; category: string; unit: string; in_stock: number };

export default function AdminProductsPage() {
  const [products, setProducts] = useState<Product[]>([]);
  const [search, setSearch] = useState("");
  const [showAdd, setShowAdd] = useState(false);
  const [newProduct, setNewProduct] = useState({ name: "", price: "", category: "", unit: "piece" });

  const fetchProducts = useCallback(() => { fetch("/api/products").then(r => r.json()).then(setProducts); }, []);
  useEffect(() => { fetchProducts(); }, [fetchProducts]);

  async function toggleStock(p: Product) {
    await fetch(`/api/products/${p.id}`, { method: "PATCH", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ in_stock: !p.in_stock }) });
    fetchProducts();
  }

  async function addProduct() {
    if (!newProduct.name || !newProduct.price || !newProduct.category) { alert("Fill in all fields"); return; }
    await fetch("/api/products", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ ...newProduct, price: parseFloat(newProduct.price) }) });
    setNewProduct({ name: "", price: "", category: "", unit: "piece" });
    setShowAdd(false);
    fetchProducts();
  }

  async function deleteProduct(id: number) {
    if (!confirm("Delete this product?")) return;
    await fetch(`/api/products/${id}`, { method: "DELETE" });
    fetchProducts();
  }

  const filtered = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));
  const categories = [...new Set(products.map(p => p.category))].sort();

  return (
    <div>
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-xl font-bold text-gray-800">Products ({products.length})</h2>
        <button onClick={() => setShowAdd(!showAdd)} className="btn btn-primary px-4 py-2">{showAdd ? "Cancel" : "+ Add Product"}</button>
      </div>

      {showAdd && (
        <div className="card p-4 mb-4">
          <h3 className="font-bold text-gray-800 mb-3">New Product</h3>
          <div className="grid grid-cols-2 gap-3">
            <input type="text" placeholder="Product Name" value={newProduct.name} onChange={e => setNewProduct(p => ({ ...p, name: e.target.value }))} className="input col-span-2" />
            <input type="number" placeholder="Price" value={newProduct.price} onChange={e => setNewProduct(p => ({ ...p, price: e.target.value }))} className="input" />
            <select value={newProduct.unit} onChange={e => setNewProduct(p => ({ ...p, unit: e.target.value }))} className="input">
              {["piece", "pack", "kg", "bottle", "bag", "jar", "bar"].map(u => <option key={u} value={u}>{u}</option>)}
            </select>
            <select value={newProduct.category} onChange={e => setNewProduct(p => ({ ...p, category: e.target.value }))} className="input">
              <option value="">Select Category</option>
              {categories.map(c => <option key={c} value={c}>{c}</option>)}
              <option value="Other">Other</option>
            </select>
            <button onClick={addProduct} className="btn btn-primary py-2">Add Product</button>
          </div>
        </div>
      )}

      <input type="text" placeholder="Search products..." value={search} onChange={e => setSearch(e.target.value)} className="input mb-4" />

      <div className="card divide-y divide-gray-100">
        {filtered.map(product => (
          <div key={product.id} className="flex items-center justify-between p-4">
            <div className="flex-1">
              <div className="flex items-center gap-2">
                <h3 className="text-sm font-medium text-gray-800">{product.name}</h3>
                {!product.in_stock && <span className="badge bg-red-100 text-red-600">Out of Stock</span>}
              </div>
              <div className="text-xs text-gray-400 mt-0.5">{product.category} &middot; &#8377;{product.price}/{product.unit}</div>
            </div>
            <div className="flex items-center gap-2">
              <button onClick={() => toggleStock(product)} className={`btn text-xs px-3 py-1.5 ${product.in_stock ? "btn-ghost" : "btn-danger"}`}>
                {product.in_stock ? "In Stock" : "Out of Stock"}
              </button>
              <button onClick={() => deleteProduct(product.id)} className="btn btn-muted text-xs px-3 py-1.5 hover:!bg-red-50 hover:!text-red-600">Delete</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
